package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;

class ClonePair10929DifferenceFindingTest {

    private final ClonePair10929 subject = new ClonePair10929();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: return_value.
     * Difference manifestation: the methods return different values.
     */
    @Test
    @BehavioralDifference(DifferenceType.RETURN_VALUE)
    void methodsDisagreeOnGeneratedInput() {
        Object[] inputs = new Object[]{Integer.MAX_VALUE};
        InvocationOutcome method1Outcome = capture(values -> subject.method1(((Integer) values[0]).intValue()), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2(((Integer) values[0]).intValue()), inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Integer(1)",
            null,
            "java.lang.Object[][Integer(2147483647)]",
            "java.lang.Object[][Integer(2147483647)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Integer(65535)",
            null,
            "java.lang.Object[][Integer(2147483647)]",
            "java.lang.Object[][Integer(2147483647)]"
        );
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }
}
